package com.company.supervision.api;import com.company.supervision.application.messaging.WecomMediaService;import com.company.supervision.entity.dto.ApiResult;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;@RestController @RequestMapping("/messages/media")public class MediaController{private final WecomMediaService s;public MediaController(WecomMediaService s){this.s=s;}@PostMapping("/upload")public ApiResult<?>upload(@RequestParam MultipartFile file,@RequestParam String type,@RequestParam String channel,@RequestParam(required=false)Long webhookId)throws Exception{return ApiResult.ok(s.upload(file,type,channel,webhookId));}}